<?php $pageTitle = 'Withdrawal Management'; require __DIR__ . '/../../includes/layouts/admin-header.php'; ?>
<?php if (!all_withdrawals()): ?><section class="empty-state"><span class="empty-state__icon">WD</span><h2>No withdrawal requests</h2><p>Pending withdrawals will appear here for approval or rejection.</p></section><?php else: ?>
<section class="table-wrap responsive-table"><table><thead><tr><th>ID</th><th>User</th><th>Amount</th><th>Destination</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach (array_reverse(all_withdrawals()) as $row): ?><tr data-search-row><td data-label="ID"><?= e($row['id']) ?></td><td data-label="User"><?= e($row['username'] ?? 'customer') ?></td><td data-label="Amount"><?= e(money($row['amount'])) ?></td><td data-label="Destination"><?= e($row['destination']) ?></td><td data-label="Status"><span class="<?= status_class($row['status']) ?>"><?= e($row['status']) ?></span></td><td data-label="Action"><?php if ($row['status'] === 'Pending'): ?><form method="post" class="admin-actions" data-confirm="Process this withdrawal request?"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><input type="hidden" name="user_id" value="<?= e((string) ($row['user_id'] ?? 0)) ?>"><input type="hidden" name="id" value="<?= e($row['id']) ?>"><button class="button button--primary" name="action" value="approve_withdrawal">Approve</button><button class="button button--danger" name="action" value="reject_withdrawal">Reject</button></form><?php else: ?>Reviewed<?php endif; ?></td></tr><?php endforeach; ?></tbody></table></section>
<?php endif; require __DIR__ . '/../../includes/layouts/admin-footer.php'; ?>
